SELECT COUNT(device_id) AS device_count
FROM device_locations
WHERE location = 'New York';

SELECT device_id, service
FROM device_services
WHERE service = 'Temperature';

SELECT COUNT(error_id) AS total_errors
FROM device_errors
WHERE device_id = 0;

SELECT error_message
FROM device_errors
WHERE error_timestamp > '2022-01-01 12:00:00';

SELECT error_message
FROM device_errors
ORDER BY error_message;

SELECT COUNT(*) AS log_count
FROM device_logs
WHERE device_id = 0;

SELECT COUNT(device_id) AS device_count
FROM device_firmware
WHERE firmware_version = '1.1.0';

SELECT device_id, location
FROM devices
ORDER BY location;

SELECT COUNT(*) AS register_action_count
FROM actions
WHERE device_id = 1 AND action_type = 'register';

SELECT COUNT(service) AS service_count
FROM device_services
WHERE device_id = 0;
